(function(){var loadHandler=window['sl_{5EFD177F-AF92-4193-97C3-EF2BE7F6A018}'];loadHandler&&loadHandler(77, '<div id="spr0_7f918d0"><div id="spr1_7f918d0" class="kern slide"><img id="img2_7f918d0" src="data:image/png;base64," width="960px" height="540px" alt="" style="left:0px;top:0px;"/><div id="spr3_7f918d0" style="left:894px;"><a id="hl0_7f918d0" href="#" onclick="document.getElementById(\'coreSpr_16181566\').getCore().processTriggerEffect(this);document.getElementById(\'coreSpr_16181566\').getCore().gotoSlide(0, this);return false;"><img id="img0_7f918d0" src="data:image/png;base64," width="65" height="66" alt="" style="left:0.138px;top:0.077px;"/></a></div><div id="spr4_7f918d0" style="left:700.645px;top:3.777px;"><img id="img1_7f918d0" src="data:image/png;base64," width="208" height="50" alt="A close-up of a pen  AI-generated content may be incorrect." style="left:0.007px;top:0.201px;"/></div></div><div id="spr2_7f918d0" class="kern slide"><div id="spr5_7f918d0" style="left:335.369px;top:3.514px;"><div style="width:0px;"><span id="txt0_7f918d0" data-width="273.781250" style="left:7.2px;top:13.223px;">PARENTAL CARE</span></div></div><div id="spr6_7f918d0" style="left:3.727px;top:60.213px;"><div style="width:0px;"><span id="txt1_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:1.782px;">•</span> <span id="txt2_7f918d0" class="relpos" data-width="471.660156" style="left:18.198px;top:-1.035px;">Different animals show different degrees of parental care.</span></div><div style="width:0px;"><span id="txt3_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:33.382px;">•</span> <span id="txt4_7f918d0" class="relpos" data-width="902.900391" style="left:18.198px;top:30.565px;">Some animals like the insects, frogs and certain fish, do not display any parental care, they simply lay their eggs</span></div><div style="width:0px;"><span id="txt5_7f918d0" data-width="132.705078" style="left:25.2px;top:52.165px;">and move away.</span></div><div style="width:0px;"><span id="txt6_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:86.582px;">•</span> <span id="txt7_7f918d0" class="relpos" data-width="461.132813" style="left:18.198px;top:83.765px;">Birds and mammals show a high degree of parental care.</span></div><div style="width:0px;"><span id="txt8_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:118.182px;">•</span> <span id="txt9_7f918d0" class="relpos" data-width="922.021484" style="left:18.198px;top:115.365px;">Those animals that show little or no parental care produce many offspring in the hope that some of the off-spring</span></div><div style="width:0px;"><span id="txt10_7f918d0" data-width="173.242188" style="left:25.2px;top:136.965px;">survive to adulthood.</span></div><div style="width:0px;"><span id="txt11_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:171.382px;">•</span> <span id="txt12_7f918d0" class="relpos" data-width="481.054688" style="left:18.198px;top:168.565px;">Some snakes and geckos take care of the eggs that are laid.</span></div><div style="width:0px;"><span id="txt13_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:202.982px;">•</span> <span id="txt14_7f918d0" class="relpos" data-width="591.689453" style="left:18.198px;top:200.165px;">Crocodiles bury their eggs and protect their young as soon as they hatch.</span></div><div style="width:0px;"><span id="txt15_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:234.582px;">•</span> <span id="txt16_7f918d0" class="relpos" data-width="630.830078" style="left:18.198px;top:231.765px;">They even carry their young in their mouths so that the young may get to the </span></div><div style="width:0px;"><span id="txt17_7f918d0" data-width="104.169922" style="left:654.35px;top:231.765px;">water safely.</span></div><div style="width:0px;"><span id="txt18_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:266.182px;">•</span> <span id="txt19_7f918d0" class="relpos" data-width="805.576172" style="left:18.198px;top:263.365px;">Birds display a high degree of parental care. The eggs are protected and incubated until they hatch.</span></div><div style="width:0px;"><span id="txt20_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:297.782px;">•</span> <span id="txt21_7f918d0" class="relpos" data-width="569.423828" style="left:18.198px;top:294.965px;">Young chicks are fed and protected until they are totally independent.</span></div><div style="width:0px;"><span id="txt22_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:329.382px;">•</span> <span id="txt23_7f918d0" class="relpos" data-width="903.837891" style="left:18.198px;top:326.565px;">Mammals show the highest degree of parental care. The young develop in the uterus where they are protected</span></div><div style="width:0px;"><span id="txt24_7f918d0" data-width="534.384766" style="left:25.2px;top:348.165px;">and provided with nutrients and oxygen from the mother\'s blood.</span></div><div style="width:0px;"><span id="txt25_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:382.582px;">•</span> <span id="txt26_7f918d0" class="relpos" data-width="662.187500" style="left:18.198px;top:379.765px;">Newly born mammals are fed with milk that is produced by the mammary glands.</span></div><div style="width:0px;"><span id="txt27_7f918d0" class="nokern relpos" dir="auto" style="left:7.2px;top:414.182px;">•</span> <span id="txt28_7f918d0" class="relpos" data-width="724.707031" style="left:18.198px;top:411.365px;">Young humans are taught to walk, talk and are fed until they can function independently.</span></div></div></div></div>', '{"s":[]}');})();